const body = $input.first().json.body || $input.first().json;
const entry = (body.entry || [])[0];
if (!entry) return [];
const change = (entry.changes || [])[0];
if (!change || change.field !== 'messages') return [];
const value = change.value || {};
const msg = (value.messages || [])[0];
if (!msg) return [];

const contact = (value.contacts || [])[0];
const phoneNumberId = value.metadata?.phone_number_id || '';

let normalized = (msg.from || '').replace(/[\s\-\(\)\+]/g, '');
if (normalized.startsWith('0034')) normalized = normalized.slice(4);
if (normalized.length === 9) normalized = '34' + normalized;

const result = {
  from: msg.from,
  from_name: contact?.profile?.name || msg.from,
  normalized_phone: normalized,
  message_id: msg.id,
  timestamp: msg.timestamp,
  msg_type: msg.type,
  phone_number_id: phoneNumberId,
  media_id: null,
  mime_type: null,
  caption: null,
  filename: null,
  text_body: null,
  button_reply_id: null,
  button_reply_title: null,
  list_reply_id: null,    // PR_BOT_2
  list_reply_title: null,
};

switch (msg.type) {
  case 'image':
    result.media_id = msg.image.id;
    result.mime_type = msg.image.mime_type;
    result.caption = msg.image.caption || null;
    result.filename = `whatsapp-${msg.from}-${Date.now()}.jpg`;
    break;
  case 'document':
    result.media_id = msg.document.id;
    result.mime_type = msg.document.mime_type;
    result.caption = msg.document.caption || null;
    result.filename = msg.document.filename || `whatsapp-${msg.from}-${Date.now()}.pdf`;
    break;
  case 'audio':
    result.media_id = msg.audio.id;
    result.mime_type = msg.audio.mime_type;
    result.filename = `voice-${msg.from}-${Date.now()}.ogg`;
    break;
  case 'text':
    result.text_body = msg.text?.body || null;
    break;
  case 'interactive':
    if (msg.interactive?.type === 'button_reply') {
      result.button_reply_id = msg.interactive.button_reply.id;
      result.button_reply_title = msg.interactive.button_reply.title;
    } else if (msg.interactive?.type === 'list_reply') {
      // // PR_BOT_2: list_reply (selección org)
      result.list_reply_id = msg.interactive.list_reply.id;
      result.list_reply_title = msg.interactive.list_reply.title;

      // CREAR_DOC_SELECT_V1 (fix 088): las selecciones de lista de
      // desambiguación de crear_doc (elegir movimiento/cliente) vuelven al
      // AGENTE como texto para re-emitir crear_doc_desde_movimiento con los ids
      // resueltos (el prompt 088 lo espera). Sin esto se tratan como botón, no
      // matchean en Router Botones Movimientos y se descartan en silencio.
      if (/^crear_doc_(mov|cli):/.test(result.list_reply_id || '')) {
        result.msg_type = 'text';
        result.text_body = result.list_reply_id;
      }
      // // PR_BOT_2_1: no sobrescribir text_body con list_reply_title
      // (contaminación cross-feature; los downstream que necesiten texto
      // ya tienen list_reply_title explícito).
    }
    break;
}


return [{ json: result }];

// ── HMAC v2 helper (FacturaIA SaaS Fase 2.15, 2026-05-30) ───────────────
// Firma cada request server-to-server con `X-Service-Signature: t=<unix>,v1=<hex>`
// donde v1 = HMAC-SHA256(SIGNING_SECRET, `${t}.${METHOD}.${pathWithSearch}.${sha256(bodyStr)}`).
// El backend acepta legacy hasta SIGNING_LEGACY_UNTIL (2026-07-30); migramos antes.
const crypto = require('crypto');
const SIGNING_SECRET = $env.FACTURAIA_SIGNING_SECRET;
if (!SIGNING_SECRET) throw new Error('FACTURAIA_SIGNING_SECRET ausente en env n8n');
function _pathSearch(urlStr) {
  const m = /^https?:\/\/[^/]+(\/[^?#]*)(\?[^#]*)?/.exec(urlStr);
  if (!m) throw new Error('invalid url for signing: ' + urlStr);
  return (m[1] || '/') + (m[2] || '');
}
async function signedHttpRequest(opts) {
  const pathWithSearch = _pathSearch(opts.url);
  const t = Math.floor(Date.now()/1000);
  let bodyStr = '';
  if (opts.body !== undefined && opts.body !== null) {
    bodyStr = typeof opts.body === 'string' ? opts.body : JSON.stringify(opts.body);
  }
  const bodyHash = crypto.createHash('sha256').update(bodyStr, 'utf8').digest('hex');
  const payload = `${t}.${(opts.method || 'GET').toUpperCase()}.${pathWithSearch}.${bodyHash}`;
  const sig = crypto.createHmac('sha256', SIGNING_SECRET).update(payload, 'utf8').digest('hex');
  const headers = Object.assign({}, opts.headers || {}, {
    'X-Service-Signature': `t=${t},v1=${sig}`,
    'Content-Type': 'application/json',
  });
  const newOpts = Object.assign({}, opts, { headers, body: bodyStr, json: false });
  const resp = await this.helpers.httpRequest(newOpts);
  if (typeof resp === 'string') { try { return JSON.parse(resp); } catch { return resp; } }
  return resp;
}
// ───────────────────────────────────────────────────────────────────────

// Resuelve org del remitente via /api/internal/whatsapp/resolve-context
// (single source of truth: sticky whatsapp_org_selection -> active_org_id ->
// multi_org_pendiente). En multi_org_pendiente prepara la subida pendiente.
const SUPABASE_URL = 'https://lahqlyaxvobqjgdiftag.supabase.co';
const SUPABASE_KEY = $env.SUPABASE_SERVICE_ROLE_KEY;
const BASE = $env.FACTURAIA_BASE_URL || 'https://app.tufacturaia.com';
const parsed = $('Parsear Mensaje').first().json;
// Sanitiza filename (de Meta, atacante-controlado en PDFs) para evitar path
// traversal al construir storage_path/pending_path. Mismo regex que ingesta/route.ts.
const filename = (parsed.filename || 'documento').replace(/[^a-zA-Z0-9.\-_]/g, '_').slice(0, 200);
const mimeType = parsed.mime_type || 'application/octet-stream';
const from = parsed.from;
const fromName = parsed.from_name;
const phoneNumberId = parsed.phone_number_id;
const phone = parsed.normalized_phone || (from || '').replace(/[\s\-\(\)\+]/g, '');

let ctx;
try {
  ctx = await signedHttpRequest.call(this, {
    method: 'POST',
    url: `${BASE}/api/internal/whatsapp/resolve-context`,
    headers: { 'Content-Type': 'application/json' },
    body: { from_phone: phone },
    json: true,
  });
} catch (err) {
  return [{ json: { matched: false, multi_org_pending: false, reason: 'resolve_context_unreachable', from, from_name: fromName, phone_number_id: phoneNumberId } }];
}

if (ctx && ctx.reason === 'multi_org_pendiente') {
  const pendingPath = `_pending/${phone}/${Date.now()}-${filename}`;
  return [{ json: {
    matched: false,
    multi_org_pending: true,
    candidate_orgs: ctx.candidate_orgs || [],
    from,
    from_name: fromName,
    phone,
    phone_number_id: phoneNumberId,
    filename,
    mime_type: mimeType,
    pending_path: pendingPath,
    supabase_url: SUPABASE_URL,
    supabase_key: SUPABASE_KEY,
  }, binary: $input.first().binary }];
}

// INGESTA_ALWAYS_ASK_MULTIORG: aunque resolve-context resuelva via sticky,
// si hay 2+ orgs siempre preguntar en ingesta (cada foto es independiente).
if (ctx && ctx.matched && Array.isArray(ctx.candidate_orgs) && ctx.candidate_orgs.length >= 2) {
  const pendingPath = `_pending/${phone}/${Date.now()}-${filename}`;
  return [{ json: {
    matched: false,
    multi_org_pending: true,
    candidate_orgs: ctx.candidate_orgs,
    from,
    from_name: fromName,
    phone,
    phone_number_id: phoneNumberId,
    filename,
    mime_type: mimeType,
    pending_path: pendingPath,
    supabase_url: SUPABASE_URL,
    supabase_key: SUPABASE_KEY,
  }, binary: $input.first().binary }];
}

if (!ctx || !ctx.matched || !ctx.org_id) {
  return [{ json: { matched: false, multi_org_pending: false, reason: (ctx && ctx.reason) || 'sin_org', from, from_name: fromName, phone_number_id: phoneNumberId } }];
}

const ORG_ID = ctx.org_id;
const ORG_NOMBRE = ctx.org_nombre || '';

const buffer = await this.helpers.getBinaryDataBuffer(0, 'data');
const base64 = buffer.toString('base64');
const storagePath = `${ORG_ID}/${Date.now()}-${filename}`;

return [{
  json: {
    matched: true,
    multi_org_pending: false,
    org_id: ORG_ID,
    org_nombre: ORG_NOMBRE,
    filename: filename,
    storage_path: storagePath,
    mime_type: mimeType,
    from: from,
    from_name: fromName,
    base64: base64,
    phone_number_id: phoneNumberId,
    supabase_url: SUPABASE_URL,
    supabase_key: SUPABASE_KEY,
    documento_url: `${SUPABASE_URL}/storage/v1/object/public/facturas/${storagePath}`
  },
  binary: $input.first().binary
}];

