let resolveResp;
try {
  resolveResp = await signedHttpRequest.call(this, {
    method: 'POST',
    url: `${BASE}/api/internal/whatsapp/resolve-context`,
    headers: {
      'Content-Type': 'application/json',
    },
    body: { from_phone: phone, features_to_check: ['generador_voz'] },
