const isMultiPending = resolveResp.reason === 'multi_org_pendiente';

if (resolveResp.matched && featOk) {
  return [{ json: {
    matched: true,
    org_id: resolveResp.org_id,
    org_nombre: resolveResp.org_nombre,
    user_id: resolveResp.user_id,
