// CONSULTA_COPILOTO_V1 — rama a insertar en "Parsear y Calcular Totales"
// (receptor pqSWkDIHqmSVHotB, issue 093 Fase 1). El agente clasifica las
// PREGUNTAS de SOLO LECTURA sobre datos de la org y emite
// { tipo:'consulta_copiloto', pregunta:'<texto del usuario>' }. Esta rama
// relaya la pregunta al puente server /api/internal/whatsapp/copiloto
// (Copiloto v2 — mismo cerebro que la web, sus 10 tools de lectura) por HMAC
// (helper signedHttpRequest ya presente) y enruta la respuesta a los caminos
// de envío YA EXISTENTES, SIN nodos ni conexiones nuevas:
//   reply       → texto plano  (error:true + conversacional:true → Responder Error Agente)
//   upsell      → texto plano  (mensaje del endpoint)
//   usage_cap   → texto plano  (mensaje del endpoint)
//   org_pendiente (multi-org ≥2) → enviar_lista_multi_org (selector existente)
//   org_pendiente (sin_org / no registrado) / error → texto plano guía
// El copiloto SOLO LEE; nunca escribe sin confirmación (eso es Fase 2).
if (data.tipo === 'consulta_copiloto') {
  const agentIn = $('Preparar Input Agente').first().json;
  const APP = $env.APP_URL || 'https://app.tufacturaia.com';
  const pregunta = String(data.pregunta || data.message || data.mensaje || data.texto || '').trim();

  const base = {
    raw_from: agentIn.raw_from,
    phone_number_id: agentIn.phone_number_id,
    normalized_phone: agentIn.normalized_phone || agentIn.sessionId,
    data: { tipo: 'consulta_copiloto' },
    resumen: '', totales: { base: 0, iva: 0, total: 0 }, nuevos_productos: [],
  };
  const texto = (m) => [{ json: { ...base, error: true, conversacional: true, message: m } }];

  if (!pregunta) {
    return texto('¿Qué quieres consultar? Por ejemplo: "¿cuánto me deben?" o "ventas por cliente este mes".');
  }

  let res;
  try {
    res = await signedHttpRequest.call(this, {
      method: 'POST',
      url: `${APP}/api/internal/whatsapp/copiloto`,
      body: {
        phone_number_id: agentIn.phone_number_id,
        from_phone: agentIn.normalized_phone || agentIn.raw_from,
        org_id: agentIn.org_id || agentIn.active_org_id || undefined,
        message: pregunta,
      },
      timeout: 45000,
    });
  } catch (e) {
    return texto('No he podido consultar tus datos ahora mismo. Inténtalo en un momento.');
  }

  if (res && res.reply && res.text) return texto(String(res.text));
  if (res && (res.upsell || res.usage_cap)) {
    return texto(String(res.mensaje || 'Esa consulta no está disponible ahora mismo.'));
  }
  if (res && res.org_pendiente) {
    const cands = Array.isArray(res.candidate_orgs) ? res.candidate_orgs : [];
    if (cands.length >= 2) {
      return [{ json: { ...base, error: false, enviar_lista_multi_org: true,
        message: 'Vale, ¿de qué empresa?', candidate_orgs: cands.slice(0, 10) } }];
    }
    return texto('No encuentro tu empresa en FacturaIA. Entra en la web para vincular tu número de WhatsApp.');
