  const base = {
    raw_from: agentIn.raw_from,
    phone_number_id: agentIn.phone_number_id,
    normalized_phone: agentIn.normalized_phone || agentIn.sessionId,
    data: { tipo: 'accion_copiloto' },
    resumen: '', totales: { base: 0, iva: 0, total: 0 }, nuevos_productos: [],
  };
  const texto = (m) => [{ json: { ...base, error: true, conversacional: true, message: m } }];

  if (!mensaje) {
    return texto('¿Qué quieres que haga? Por ejemplo: "marca cobrada la factura A2026-0001".');
  }

  let res;
  try {
    res = await signedHttpRequest.call(this, {
      method: 'POST',
      url: `${APP}/api/internal/whatsapp/copiloto`,
      body: {
        phone_number_id: agentIn.phone_number_id,
        from_phone: agentIn.normalized_phone || agentIn.raw_from,
        org_id: agentIn.org_id || agentIn.active_org_id || undefined,
        message: mensaje,
      },
      timeout: 45000,
    });
  } catch (_e) {
    return texto('No he podido preparar la acción ahora mismo. Inténtalo en un momento.');
  }

  // Propuesta destructiva → botones de confirmación (id lleva el pending_id).
  if (res && res.confirm && res.pending_id) {
    const warns = Array.isArray(res.warnings) && res.warnings.length
      ? '\n\n⚠️ ' + res.warnings.join('\n⚠️ ')
      : '';
    return [{ json: {
      ...base,
      error: false,
      enviar_botones_copiloto: true,
      pending_id: String(res.pending_id),
      message: String(res.summary || '¿Confirmas esta acción?') + warns,
    } }];
  }
  if (res && res.reply && res.text) return texto(String(res.text));
  if (res && (res.upsell || res.usage_cap)) {
    return texto(String(res.mensaje || 'Esa acción no está disponible ahora mismo.'));
  }
  if (res && res.org_pendiente) {
    const cands = Array.isArray(res.candidate_orgs) ? res.candidate_orgs : [];
    if (cands.length >= 2) {
      return [{ json: { ...base, error: false, enviar_lista_multi_org: true,
        message: 'Vale, ¿de qué empresa?', candidate_orgs: cands.slice(0, 10) } }];
    }
    return texto('No encuentro tu empresa en FacturaIA. Entra en la web para vincular tu número de WhatsApp.');
  }
  return texto('No he podido completar la acción ahora mismo.');
