// ── BRANCH NUEVO: convertir_presupuesto ──
// Si el agente devolvió tipo='convertir_presupuesto', el JSON NO trae lineas
// (correcto — la conversión copia las del presupuesto origen, no las inventa).
// Hacemos lookup directo a Supabase para obtener totales reales y construir
// un resumen específico para el botón de confirmación.
if (data.tipo === 'convertir_presupuesto') {
  // v2 — ambiguous_handler: si el agente devuelve un error controlado con
  // mensaje propio (desambiguación, no encontrado, etc.), propagamos su
  // mensaje al user en vez de sobrescribir con el genérico.
  if (data.error && data.mensaje) {
    // v3 — persist_listado_on_ambiguo: si trae candidates (lista de
    // presupuestos del CASO 2), persistimos chat_state para que el
    // siguiente turno ("qué tiene el 2") pueda resolver el UUID.
    // v4 — persist_listado_clean: incluir draft:null y current_doc:null para
    // que el merge shallow del endpoint borre cualquier draft viejo de la sesión
    // previa (si el user salta de un flujo a otro listado nuevo).
    if (Array.isArray(data.candidates) && data.candidates.length > 0) {
      try {
        const APP_URL = $env.APP_URL;
        const agentInput = $('Preparar Input Agente').first().json;
        // phone_e164_normalize_v1: añadir '+' si falta — endpoint exige E.164.
const _phRaw = (agentInput.normalized_phone || agentInput.sessionId || '').trim();
const phoneUser = _phRaw && !_phRaw.startsWith('+') ? '+' + _phRaw.replace(/^\++/, '') : _phRaw;
        const phoneReceptorId = agentInput.phone_number_id || '';
        const orgId = agentInput.org_id || '';
        if (APP_URL && SIGNING_SECRET && phoneUser && phoneReceptorId && orgId) {
          await signedHttpRequest.call(this, {
            method: 'POST',
            url: `${APP_URL}/api/internal/voice/chat-state`,
            headers: {
              'Content-Type': 'application/json',
            },
            body: {
              phone_user: phoneUser,
              phone_receptor_id: phoneReceptorId,
              org_id: orgId,
              current_view: 'mostrando_listado',
              state_json: {
                last_listado: {
                  kind: 'presupuestos',
                  items: data.candidates,
                  ts: new Date().toISOString(),
                },
                last_intent: data.tipo || 'convertir_presupuesto',
                draft: null,
                current_doc: null,
                resolved_slot: null,
              },
            },
            json: true,
            timeout: 3000,
          });
        }
      } catch (_e) {
        // fail-open: el listado ya se envía al user; perder persist es degradación, no error.
      }
    }
    return [{ json: {
      error: true,
      message: data.mensaje,
      raw_from: $('Preparar Input Agente').first().json.raw_from,
      phone_number_id: $('Preparar Input Agente').first().json.phone_number_id
    }}];
  }
  if (!data.presupuesto_id) {
    return [{ json: {
      error: true,
      message: 'No tengo el ID del presupuesto. Reformula tu mensaje indicando el numero (ej: P2026-0042).',
      raw_from: $('Preparar Input Agente').first().json.raw_from,
      phone_number_id: $('Preparar Input Agente').first().json.phone_number_id
    }}];
  }

  const SUPABASE_URL = 'https://lahqlyaxvobqjgdiftag.supabase.co';
  const SUPABASE_KEY = $env.SUPABASE_SERVICE_ROLE_KEY;
  const orgId = $('Preparar Input Agente').first().json.org_id;

  const presResp = await signedHttpRequest.call(this, {
    method: 'GET',
    url: `${SUPABASE_URL}/rest/v1/presupuestos?id=eq.${data.presupuesto_id}&org_id=eq.${orgId}&select=id,num,fecha,base,total,estado,cliente_id,lineas,clientes(nombre,nif)`,
    headers: { 'apikey': SUPABASE_KEY, 'Authorization': `Bearer ${SUPABASE_KEY}` },
    json: true
  });

  if (!presResp || presResp.length === 0) {
    return [{ json: {
      error: true,
      message: 'No encuentro ese presupuesto en tu organizacion. Verifica el numero.',
      raw_from: $('Preparar Input Agente').first().json.raw_from,
      phone_number_id: $('Preparar Input Agente').first().json.phone_number_id
    }}];
  }

  const pres = presResp[0];
  const baseTotal = parseFloat(pres.base) || 0;
  const total = parseFloat(pres.total) || 0;
  const ivaTotal = total - baseTotal;
  const fmtConv = n => n.toFixed(2).replace('.', ',');

  // // PR_BOT_1_2: cabecera con org si multi-org
  const _agentIn = $('Preparar Input Agente').first().json;
  // PR_BOT_3_1: siempre mostrar org en cabecera si está disponible.
  const _multiSuffix = _agentIn.org_nombre ? ` · ${_agentIn.org_nombre}` : '';
  let resumen = `🔄 *CONVERTIR PRESUPUESTO → FACTURA${_multiSuffix}*\n`;
  resumen += `Origen: ${pres.num}\n`;
  resumen += `Cliente: ${pres.clientes?.nombre || 'Sin nombre'}\n`;
  if (pres.fecha) resumen += `Fecha presupuesto: ${pres.fecha}\n`;
  resumen += `\n`;

  const lineasPres = Array.isArray(pres.lineas) ? pres.lineas : [];
  lineasPres.forEach(l => {
    const cant = l.cantidad || 1;
    const precio = l.precio_unitario || 0;
    const concepto = l.concepto || l.descripcion || 'Servicio';
    resumen += `• ${cant}x ${concepto}: ${fmtConv(precio)} EUR/u = ${fmtConv(cant * precio)} EUR`;
    const tags = [];
    if ((l.descuento_pct || 0) > 0) tags.push(`-${l.descuento_pct}%`);
    if (l.iva_pct !== undefined && l.iva_pct !== 21) tags.push(`IVA ${l.iva_pct}%`);
    if (tags.length) resumen += ` (${tags.join(', ')})`;
    resumen += `\n`;
  });
  if (lineasPres.length === 0) {
    resumen += `_(Las lineas se copiaran del presupuesto al confirmar)_\n`;
  }

  resumen += `\nBase: ${fmtConv(baseTotal)} EUR\n`;
  resumen += `IVA: ${fmtConv(ivaTotal)} EUR\n`;
  resumen += `*TOTAL: ${fmtConv(total)} EUR*`;

  if (pres.estado === 'facturado') {
    resumen += `\n\n⚠️ _Este presupuesto ya esta facturado. Si confirmas, te devolvere la factura existente sin duplicar._`;
  }

  return [{ json: {
    error: false,
    data: { ...data, presupuesto_num: pres.num, total_estimado: total, cliente: { nombre: pres.clientes?.nombre || data.cliente?.nombre || 'Sin nombre' } },
    resumen: _withQuotaTail(resumen),
    totales: { base: baseTotal, iva: ivaTotal, total },
    nuevos_productos: [],
    raw_from: $('Preparar Input Agente').first().json.raw_from,
    phone_number_id: $('Preparar Input Agente').first().json.phone_number_id
  }}];
}

if (data.error) {
  return [{ json: {
    error: true,
    message: data.mensaje || 'No tengo suficiente informacion. Especifica el numero de factura o el cliente.',
    raw_from: $('Preparar Input Agente').first().json.raw_from,
    phone_number_id: $('Preparar Input Agente').first().json.phone_number_id
  } }];
}

// ── // PR_BOT_2_4: defensa precio 0 / NIF faltante ──
// El LLM puede ignorar reglas del prompt. Cortamos en el código:
// no emitimos resumen 🧾 con precio falsy ni con factura sin NIF.
{
  const _tipo = (data.tipo || 'factura').toLowerCase();
  const _lineasCheck = Array.isArray(data.lineas) ? data.lineas : [];
  const _agentInGuard = $('Preparar Input Agente').first().json;
  if (_tipo === 'factura' || _tipo === 'abono' || _tipo === 'presupuesto' || _tipo === 'proforma') {
    // Línea con precio falsy y no marcada desde_catalogo → pedir precio.
    const _linMala = _lineasCheck.find(l => {
      const p = Number(l && l.precio_unitario);
      const fromCat = l && l.desde_catalogo === true;
      return !fromCat && (!Number.isFinite(p) || p <= 0);
    });
    if (_linMala) {
