      const v = validateSpanishTaxId(nif);
      if (!v.valid) {
        const nombreCli = (cli.nombre || 'el cliente').toString().slice(0, 80);
        return [{ json: {
          error: true,
          conversacional: true,
          message: `El NIF "${nif}" no es válido. Acepto DNI (8 dígitos+letra), NIE (X/Y/Z+7 dígitos+letra) o CIF (letra empresa+7 dígitos+dígito/letra). ¿Puedes confirmar el NIF de ${nombreCli}?`,
          raw_from: _agentInGuard.raw_from,
          phone_number_id: _agentInGuard.phone_number_id,
        } }];
      }
    }
  }
}

const lineas = (data.lineas || []).map(l => {
  const base = (l.cantidad || 0) * (l.precio_unitario || 0);
  const descLinea = base * ((l.descuento_pct || 0) / 100);
  const baseNeta = base - descLinea;
  const iva = baseNeta * ((l.iva_pct || 21) / 100);
  return { ...l, base: baseNeta, iva, _isNuevo: l.desde_catalogo === false };
});

const subtotal = lineas.reduce((s, l) => s + l.base, 0);
const descGlobalPct = data.descuento_global_pct || 0;
const descGlobal = subtotal * (descGlobalPct / 100);
const baseTotal = subtotal - descGlobal;
const ivaTotal = lineas.reduce((s, l) => s + l.iva, 0) * (1 - descGlobalPct / 100);
const total = baseTotal + ivaTotal;

const fmt = n => n.toFixed(2).replace('.', ',');

const tipoEmoji = data.tipo === 'presupuesto' ? '📋'
  : data.tipo === 'proforma' ? '📄'
  : data.tipo === 'abono' ? '↩️'
  : '🧾';

// // PR_BOT_1_2: cabecera con org si multi-org
const _agentIn2 = $('Preparar Input Agente').first().json;
// PR_BOT_3_1: siempre mostrar org en cabecera si está disponible.
const _multiSuffix2 = _agentIn2.org_nombre ? ` · ${_agentIn2.org_nombre}` : '';
let resumen = `${tipoEmoji} *${(data.tipo || 'factura').toUpperCase()}${_multiSuffix2}*\n`;
resumen += `Cliente: ${data.cliente?.nombre || 'Sin nombre'}\n\n`;

lineas.forEach(l => {
  const star = l._isNuevo ? '✨ ' : '';
  resumen += `• ${l.cantidad}x ${star}${l.descripcion}: ${fmt(l.precio_unitario)} EUR/u = ${fmt(l.cantidad * l.precio_unitario)} EUR`;
  const tags = [];
  if ((l.descuento_pct || 0) > 0) tags.push(`-${l.descuento_pct}%`);
  if (l.iva_pct !== undefined && l.iva_pct !== 21) tags.push(`IVA ${l.iva_pct}%`);
  if (tags.length) resumen += ` (${tags.join(', ')})`;
  resumen += '\n';
});

resumen += '\n';
if (descGlobalPct > 0) resumen += `Dto global: ${descGlobalPct}%\n`;
resumen += `Base: ${fmt(baseTotal)} EUR\n`;
resumen += `IVA: ${fmt(ivaTotal)} EUR\n`;
resumen += `*TOTAL: ${fmt(total)} EUR*`;

const nuevos = lineas.filter(l => l._isNuevo).map(l => l.descripcion);
if (nuevos.length > 0) {
  resumen += `\n\n✨ _Productos nuevos (no estan en tu catalogo): ${nuevos.join(', ')}_`;
}

return [{ json: {
  error: false,
  data,
  resumen: _withQuotaTail(resumen),
  totales: { base: baseTotal, iva: ivaTotal, total },
  nuevos_productos: lineas.filter(l => l._isNuevo).map(l => ({
    nombre: l.descripcion,
    precio_orientativo: l.precio_unitario,
    iva_pct: l.iva_pct || 21
  })),
  raw_from: $('Preparar Input Agente').first().json.raw_from,
  phone_number_id: $('Preparar Input Agente').first().json.phone_number_id
}}];

