// Firma cada request server-to-server con `X-Service-Signature: t=<unix>,v1=<hex>`
// donde v1 = HMAC-SHA256(SIGNING_SECRET, `${t}.${METHOD}.${pathWithSearch}.${sha256(bodyStr)}`).
// El backend acepta legacy hasta SIGNING_LEGACY_UNTIL (2026-07-30); migramos antes.
const crypto = require('crypto');
const SIGNING_SECRET = $env.FACTURAIA_SIGNING_SECRET;
if (!SIGNING_SECRET) throw new Error('FACTURAIA_SIGNING_SECRET ausente en env n8n');
function _pathSearch(urlStr) {
  const m = /^https?:\/\/[^/]+(\/[^?#]*)(\?[^#]*)?/.exec(urlStr);
  if (!m) throw new Error('invalid url for signing: ' + urlStr);
  return (m[1] || '/') + (m[2] || '');
}
async function signedHttpRequest(opts) {
  const pathWithSearch = _pathSearch(opts.url);
  const t = Math.floor(Date.now()/1000);
  let bodyStr = '';
  if (opts.body !== undefined && opts.body !== null) {
    bodyStr = typeof opts.body === 'string' ? opts.body : JSON.stringify(opts.body);
  }
  const bodyHash = crypto.createHash('sha256').update(bodyStr, 'utf8').digest('hex');
  const payload = `${t}.${(opts.method || 'GET').toUpperCase()}.${pathWithSearch}.${bodyHash}`;
  const sig = crypto.createHmac('sha256', SIGNING_SECRET).update(payload, 'utf8').digest('hex');
  const headers = Object.assign({}, opts.headers || {}, {
    'X-Service-Signature': `t=${t},v1=${sig}`,
    'Content-Type': 'application/json',
  });
  const newOpts = Object.assign({}, opts, { headers, body: bodyStr, json: false });
  const resp = await this.helpers.httpRequest(newOpts);
  if (typeof resp === 'string') { try { return JSON.parse(resp); } catch { return resp; } }
  return resp;
}
// ───────────────────────────────────────────────────────────────────────

// PR_BOT_3: criterio "hay sesión activa" — antes COUNT(*) n8n_chat_histories>0
// (cualquier history previa caía en path corrección). Ahora: chat_state.current_view
// = 'awaiting_confirmation' AND state_json.draft != null AND no expirado.
// Devuelve { cnt: 0|1 } para que Tiene Sesion? siga funcionando sin cambios downstream.
const BASE = $env.FACTURAIA_BASE_URL || $env.APP_URL || 'https://app.tufacturaia.com';
const parsed = $('Parsear Mensaje').first().json;

const _phRaw = (parsed.normalized_phone || '').trim();
const phoneUser = _phRaw && !_phRaw.startsWith('+') ? '+' + _phRaw.replace(/^\++/, '') : _phRaw;
const phoneReceptorId = parsed.phone_number_id || '';

// Sin env/teléfono: fail-safe a cnt=0 (path normal). Mejor false-negative que falso path corrección.
if (!BASE || !SIGNING_SECRET || !phoneUser || !phoneReceptorId) {
  return [{ json: { cnt: 0, pr_bot_3_skip_reason: 'missing_env_or_phone' } }];
}

let orgId = '';
try {
  const ctx = await signedHttpRequest.call(this, {
    method: 'POST',
    url: BASE + '/api/internal/whatsapp/resolve-context',
    headers: { 'Content-Type': 'application/json' },
    body: { from_phone: phoneUser },
    json: true,
    timeout: 3000,
  });
  if (ctx && ctx.matched && ctx.org_id) orgId = ctx.org_id;
} catch (err) {
  return [{ json: { cnt: 0, pr_bot_3_skip_reason: 'resolve_context_error', pr_bot_3_err: String((err && err.message) || err).slice(0, 120) } }];
}

if (!orgId) {
  return [{ json: { cnt: 0, pr_bot_3_skip_reason: 'no_org_matched' } }];
}

try {
  const qs =
    'phone_user=' + encodeURIComponent(phoneUser) +
    '&phone_receptor_id=' + encodeURIComponent(phoneReceptorId) +
    '&org_id=' + encodeURIComponent(orgId);
  const st = await signedHttpRequest.call(this, {
    method: 'GET',
    url: BASE + '/api/internal/voice/chat-state?' + qs,
    headers: { },
    json: true,
    timeout: 3000,
  });
  const view = st && st.current_view ? st.current_view : null;
  const expired = st && st.expired === true;
  const draft = (st && st.state_json && typeof st.state_json === 'object') ? st.state_json.draft : null;
  const hasPendingDraft = !expired && view === 'awaiting_confirmation' && draft != null;
  return [{ json: {
    cnt: hasPendingDraft ? 1 : 0,
    pr_bot_3_view: view,
    pr_bot_3_expired: !!expired,
    pr_bot_3_org_id: orgId,
  } }];
} catch (err) {
  return [{ json: { cnt: 0, pr_bot_3_skip_reason: 'chat_state_error', pr_bot_3_err: String((err && err.message) || err).slice(0, 120) } }];
}

