// v2-process-button — gestiona button_reply de WhatsApp.
// WA_BOOST_V1_COBRO — además de los buttons clásicos (voice_confirm/cancel/correct),
// reconoce los prefixes `cobro_confirm:<factura_id>` y `cobro_reject:<factura_id>`
// generados por la rama de Fricción Inversa (B1, sprint próximo).

const buttonId = $('Parsear Mensaje').first().json.button_reply_id || '';

let intent = 'unknown';
let cobro_factura_id = null;
// EXTRACTOS_MOV_V1 (issue 038)
let mov_org_id = null;
let mov_bandeja_id = null; // EXTRACTOS_MOV_V2
let crear_doc_org_id = null; // CREAR_DOC_V1 (issue 088)

if (buttonId === 'voice_confirm') intent = 'confirm';
else if (buttonId === 'voice_cancel') intent = 'cancel';
else if (buttonId === 'voice_correct') intent = 'correct';
else if (buttonId.startsWith('copiloto_confirm:')) {
  intent = 'copiloto_confirm';
} else if (buttonId === 'copiloto_cancel') {
  intent = 'cancel';
} else if (buttonId.startsWith('cobro_confirm:')) {
  intent = 'cobro_confirm';
  cobro_factura_id = buttonId.slice('cobro_confirm:'.length) || null;
} else if (buttonId.startsWith('cobro_reject:')) {
  intent = 'cobro_reject';
  cobro_factura_id = buttonId.slice('cobro_reject:'.length) || null;
} else if (buttonId.startsWith('mov_confirmar:')) {
  // EXTRACTOS_MOV_V1 — Confirmar importación de movimientos (issue 038)
  intent = 'mov_confirmar';
  mov_org_id = buttonId.slice('mov_confirmar:'.length) || null;
} else if (buttonId === 'mov_descartar') {
  intent = 'mov_descartar';
} else if (buttonId.startsWith('mov_sip:')) {
  // EXTRACTOS_MOV_V2 — rescate por bandeja_id (Storage), no media_id
  intent = 'mov_si';
  mov_bandeja_id = buttonId.slice('mov_sip:'.length) || null;
} else if (buttonId === 'mov_no') {
  intent = 'mov_no';
} else if (buttonId.startsWith('crear_doc_confirmar:')) {
  // CREAR_DOC_V1 (issue 088) — Confirmar crear factura/gasto desde movimiento
  intent = 'crear_doc_confirmar';
  crear_doc_org_id = buttonId.slice('crear_doc_confirmar:'.length) || null;
} else if (buttonId === 'crear_doc_cancelar') {
  intent = 'crear_doc_cancel';
}

return [{ json: {
  session_id_hash: $('Hash Session').first().json.session_id_hash,
  intent,
  cobro_factura_id,
  mov_org_id,
  mov_bandeja_id,
  crear_doc_org_id,
  normalized_phone: $('Parsear Mensaje').first().json.normalized_phone,
  raw_from: $('Parsear Mensaje').first().json.from,
  phone_number_id: $('Parsear Mensaje').first().json.phone_number_id
}}];

