  return (m[1] || '/') + (m[2] || '');
}
async function signedHttpRequest(opts) {
  const pathWithSearch = _pathSearch(opts.url);
  const t = Math.floor(Date.now()/1000);
  let bodyStr = '';
  if (opts.body !== undefined && opts.body !== null) {
    bodyStr = typeof opts.body === 'string' ? opts.body : JSON.stringify(opts.body);
  }
  const bodyHash = crypto.createHash('sha256').update(bodyStr, 'utf8').digest('hex');
  const payload = `${t}.${(opts.method || 'GET').toUpperCase()}.${pathWithSearch}.${bodyHash}`;
  const sig = crypto.createHmac('sha256', SIGNING_SECRET).update(payload, 'utf8').digest('hex');
  const headers = Object.assign({}, opts.headers || {}, {
    'X-Service-Signature': `t=${t},v1=${sig}`,
    'Content-Type': 'application/json',
  });
  const newOpts = Object.assign({}, opts, { headers, body: bodyStr, json: false });
  const resp = await this.helpers.httpRequest(newOpts);
  if (typeof resp === 'string') { try { return JSON.parse(resp); } catch { return resp; } }
  return resp;
}
// ───────────────────────────────────────────────────────────────────────

const rows = $input.all();
if (!rows.length) return [{ json: { error: true, message: 'No hay sesion de factura activa.' } }];

let raw = '';
for (const row of rows) {
  const msg = row.json && row.json.message;
  if (!msg) continue;
  const msgObj = typeof msg === 'string' ? JSON.parse(msg) : msg;
  if (msgObj.type === 'ai' || msgObj.type === 'AIMessage' || msgObj.type === 'assistant') {
    raw = (msgObj.data && msgObj.data.content) || msgObj.content || (typeof msg === 'string' ? msg : JSON.stringify(msg));
    break;
  }
}

if (!raw) {
  const firstMsg = rows[0] && rows[0].json && rows[0].json.message;
  const debug = typeof firstMsg === 'string' ? firstMsg.substring(0, 200) : JSON.stringify(firstMsg).substring(0, 200);
  return [{ json: { error: true, message: 'No se encontro respuesta del agente. Debug: ' + debug } }];
}

let data;
try {
  const jsonMatch = raw.match(/\{[\s\S]*\}/);
  data = JSON.parse(jsonMatch ? jsonMatch[0] : raw);
} catch (e) {
  return [{ json: { error: true, message: 'JSON invalido del agente. Raw: ' + raw.substring(0, 200) } }];
}

const phone = $('Procesar Boton').first().json.normalized_phone;

// ── FIX multi-tenant (docs-selector 2026-06-01) ─────────────────────────
// Resolución de org vía resolve-context (single source of truth: respeta la
// sticky whatsapp_org_selection elegida en el selector multi-org). Sustituye
// la query cruda org_members[0] que emitía a la primera org arbitraria — un
// user multi-org confirmaba la factura en la empresa equivocada.
const BASE = $env.FACTURAIA_BASE_URL || $env.APP_URL || 'https://app.tufacturaia.com';
let ctx;
try {
  ctx = await signedHttpRequest.call(this, {
    method: 'POST',
    url: BASE + '/api/internal/whatsapp/resolve-context',
    body: { from_phone: phone },
    json: true,
    timeout: 6000,
  });
} catch (e) {
  return [{ json: { error: true, message: 'No pude resolver tu organizacion ahora mismo. Intentalo de nuevo en un momento.' } }];
}
if (!ctx || ctx.matched !== true || !ctx.org_id) {
  const reason = ctx && ctx.reason;
  if (reason === 'multi_org_pendiente') {
    return [{ json: { error: true, message: 'Primero dime con que empresa trabajar: escribeme "cambiar empresa".' } }];
  }
  if (reason === 'telefono_no_registrado') {
    return [{ json: { error: true, message: 'Tu telefono no esta registrado en ningun perfil de FacturaIA.' } }];
  }
  return [{ json: { error: true, message: 'No perteneces a ninguna organizacion activa.' } }];
}
const org_id = ctx.org_id;
const user_id = ctx.user_id;

// ── BRANCH: convertir_presupuesto ──
if (data.tipo === 'convertir_presupuesto') {
  if (data.error) {
    return [{ json: { error: true, message: data.mensaje || 'No pude convertir el presupuesto.' } }];
  }
  if (!data.presupuesto_id) {
    return [{ json: { error: true, message: 'Falta presupuesto_id en la respuesta del agente.' } }];
  }
  return [{ json: {
    error: false,
    flow: 'convert_presupuesto',
    org_id, user_id,
    presupuesto_id: data.presupuesto_id,
    presupuesto_num: data.presupuesto_num || null,
    total_estimado: data.total_estimado || null,
    phone,
    chat_id: phone,
    raw_from: $('Procesar Boton').first().json.raw_from,
    phone_number_id: $('Procesar Boton').first().json.phone_number_id
  }}];
}

const lineas = (data.lineas || []).map(l => ({
  concepto: l.descripcion || l.concepto,
  cantidad: l.cantidad,
  precio_unitario: l.precio_unitario,
  iva_pct: l.iva_pct || 21,
  descuento_pct: l.descuento_pct || 0,
  catalogo_id: l.catalogo_id || null
}));

return [{ json: {
  error: false,
  flow: 'generate',
  org_id,
  user_id,
  tipo: data.tipo || 'factura',
  factura_origen_id: data.factura_origen_id || null,
  // Normaliza el cliente: el AI Agent omite `id` para clientes nuevos
  // (crear:true). El contrato /api/voice/generate exige la clave, asi que
  // la fijamos a null cuando falta para no devolver 422. Defensa en
  // profundidad ademas del schema backend (.nullable().optional()).
  cliente: data.cliente ? { ...data.cliente, id: data.cliente.id ?? null } : data.cliente,
  lineas,
  descuento_global_pct: data.descuento_global_pct || 0,
  notas: data.notas || null,
  phone,
  raw_from: $('Procesar Boton').first().json.raw_from,
  phone_number_id: $('Procesar Boton').first().json.phone_number_id
}}];

