// phone_e164_normalize_v1 + state_machine_v1 — Resolver Chat State (rama sesión voz activa)
//
// La rama 'Check Sesion Voz Activa → Tiene Sesion? → Preparar Input Correccion'
// no pasa por los resolvers voz/texto principales. Sin este resolver el LLM
// pierde acceso a previous_state.last_listado, last_doc, etc.
const APP_URL = $env.APP_URL;
const upstream = $json;

const _phRaw = (upstream.normalized_phone || upstream.sessionId || '').trim();
const phoneUser = _phRaw && !_phRaw.startsWith('+') ? '+' + _phRaw.replace(/^\++/, '') : _phRaw;
const phoneReceptorId = upstream.phone_number_id || '';
const orgId = upstream.org_id || '';

if (!APP_URL || !SIGNING_SECRET || !phoneUser || !phoneReceptorId || !orgId) {
  return [{ json: { ...upstream, previous_state: null, previous_state_json: null, is_first_time: upstream.is_first_time === true, memberships_count: upstream.memberships_count || 1 } }];  // PR_BOT_1_2
}

try {
  // urlsearchparams_fix_v1: sandbox Code de n8n no expone URLSearchParams.
  const qs =
    'phone_user=' + encodeURIComponent(phoneUser) +
    '&phone_receptor_id=' + encodeURIComponent(phoneReceptorId) +
    '&org_id=' + encodeURIComponent(orgId);
  const resp = await signedHttpRequest.call(this, {
    method: 'GET',
    url: `${APP_URL}/api/internal/voice/chat-state?${qs}`,
    headers: { },
    json: true,
    timeout: 3000,
  });
  return [{ json: {
    ...upstream,
    previous_state: resp?.current_view ?? null,
    previous_state_json: resp?.state_json ?? null,
    is_first_time: upstream.is_first_time === true,  // PR_BOT_1_2
    memberships_count: upstream.memberships_count || 1,
  } }];
} catch (err) {
  const errMsg = String((err && err.message) ? err.message : err).slice(0, 120);
  return [{ json: {
    ...upstream,
    previous_state: null,
    previous_state_json: null,
    chat_state_resolve_error: errMsg,
    is_first_time: upstream.is_first_time === true,
    memberships_count: upstream.memberships_count || 1,
  } }];
}

// v5-slot-resolver-expanded — DETERMINISTA, sin LLM.
//
// Resuelve previous_state_json.resolved_slot a partir del chatInput,
// usando 8 patrones con precedencia explícita (ver TODO T1 en el patch).
//
// Patrones (en orden de PRECEDENCIA — el primero que matche gana):
//
//   1. NUM presupuesto explícito: "P2026-0018" / "p2026-0018"
//   2. SUPERLATIVO: "más caro/alto/grande" (max total) / "más barato/pequeño" (min)
//   3. FECHA: "del 18 de mayo" / "del 18-may" / "de hoy" / "de ayer" / "del 10/05"
//   4. IMPORTE: "de 289" / "289 euros" / "289,19 €" / "de 4.827"
//   5. CLIENTE: "el de Borja" (solo si listado tiene clientes MIXTOS)
//   6. NÚMERO de slot: "el 1" / "la 2" / "#3" / "n° 4" / "número 5"
//   7. ORDINAL: "primero/segundo/.../quinto" + último/última
//   8. PRONOMBRE / 1-item shortcut: "ese" / "ese mismo" / "el de antes"
//      + "qué tiene/incluye/abre" con 1 solo candidato
//
// Si nada matchea, passthrough sin tocar el state.

const upstream = $json;
const chatInput = (
  upstream.transcription ||
  upstream.correction_text ||
  upstream.chatInput ||
  ''
).toString();

let stateJson = upstream.previous_state_json;
if (typeof stateJson === 'string' && stateJson) {
  try { stateJson = JSON.parse(stateJson); } catch (_e) { stateJson = null; }
}

const items = (stateJson && stateJson.last_listado && Array.isArray(stateJson.last_listado.items))
  ? stateJson.last_listado.items
  : null;

if (!items || items.length === 0 || !chatInput) {
  return [{ json: upstream }];
}

// Normalización: lowercase + strip tildes/diacríticos.
const text = chatInput.toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '');

let resolvedIndex = null;
let matchedBy = null;

// ── 1) NUM explícito (P2026-0018) ──
if (resolvedIndex === null) {
  const m = text.match(/\bp(\d{4})[\-\s]?(\d{3,5})\b/i) || text.match(/\b(\d{4})[\-\s]?(\d{3,5})\b/);
  if (m) {
    // Buscar item cuyo num matchee (case-insensitive, ignorar guion)
    const norm = (s) => String(s || '').toLowerCase().replace(/[\s\-]/g, '');
    const target = norm('p' + m[1] + m[2]);
    const target2 = norm(m[1] + m[2]);
    for (let i = 0; i < items.length; i++) {
      const n = norm(items[i].num);
      if (n === target || n === target2 || n.endsWith(target2)) {
        resolvedIndex = i + 1;
        matchedBy = 'num';
        break;
      }
    }
  }
}

// ── 2) SUPERLATIVO (más caro / barato / grande / pequeño) ──
if (resolvedIndex === null) {
  const totals = items.map(it => Number(it.total) || 0);
  if (/\bmas\s+(caro|alto|grande|costoso|elevado)\b/.test(text)) {
    let maxIdx = 0;
    for (let i = 1; i < totals.length; i++) if (totals[i] > totals[maxIdx]) maxIdx = i;
    resolvedIndex = maxIdx + 1;
    matchedBy = 'max_total';
  } else if (/\bmas\s+(barato|bajo|pequeno|chico|reducido)\b/.test(text)) {
    let minIdx = 0;
    for (let i = 1; i < totals.length; i++) if (totals[i] < totals[minIdx]) minIdx = i;
    resolvedIndex = minIdx + 1;
    matchedBy = 'min_total';
  }
}

// ── 3) FECHA ("del 18 de mayo", "del 18-may", "de hoy", "de ayer") ──
if (resolvedIndex === null) {
  const MESES = {
    'enero':'01','febrero':'02','marzo':'03','abril':'04','mayo':'05','junio':'06',
    'julio':'07','agosto':'08','septiembre':'09','setiembre':'09','octubre':'10',
    'noviembre':'11','diciembre':'12',
    'ene':'01','feb':'02','mar':'03','abr':'04','may':'05','jun':'06',
    'jul':'07','ago':'08','sep':'09','oct':'10','nov':'11','dic':'12',
  };
  let targetMonth = null, targetDay = null;
  // "del 18 de mayo" / "del 18 may" / "18 de mayo"
  let m = text.match(/\b(\d{1,2})\s+(?:de\s+)?([a-z]{3,})/);
  if (m && MESES[m[2]]) {
    targetDay = m[1].padStart(2, '0');
    targetMonth = MESES[m[2]];
  }
  // "del 18-may" / "18-may"
  if (!targetDay) {
    m = text.match(/\b(\d{1,2})[\-\/]([a-z]{3,})/);
    if (m && MESES[m[2]]) {
      targetDay = m[1].padStart(2, '0');
      targetMonth = MESES[m[2]];
    }
  }
  // "del 18/05" / "18/05"
  if (!targetDay) {
    m = text.match(/\b(\d{1,2})[\-\/](\d{1,2})\b/);
    if (m) {
      targetDay = m[1].padStart(2, '0');
      targetMonth = m[2].padStart(2, '0');
    }
  }
  // "de hoy" / "del dia de hoy"
  if (!targetDay && /\b(de\s+)?hoy\b/.test(text)) {
    const today = new Date();
    targetDay = String(today.getUTCDate()).padStart(2, '0');
    targetMonth = String(today.getUTCMonth() + 1).padStart(2, '0');
  }
  // "de ayer"
  if (!targetDay && /\b(de\s+)?ayer\b/.test(text)) {
    const yest = new Date(Date.now() - 86400000);
    targetDay = String(yest.getUTCDate()).padStart(2, '0');
    targetMonth = String(yest.getUTCMonth() + 1).padStart(2, '0');
  }
  if (targetDay && targetMonth) {
    const target = '-' + targetMonth + '-' + targetDay;
    for (let i = 0; i < items.length; i++) {
      const f = String(items[i].fecha || '');
      if (f.endsWith(target)) {
        resolvedIndex = i + 1;
        matchedBy = 'fecha';
        break;
      }
    }
  }
}

// ── 4) IMPORTE ("de 289", "289 euros", "289,19", "4.827,90") ──
if (resolvedIndex === null) {
  // Captura número con coma decimal española y/o punto miles
  const m = text.match(/(?:de\s+|por\s+|importe\s+)?(\d{1,3}(?:[.,]\d{3})*(?:[.,]\d{1,2})?|\d+)(?:\s*(?:€|eur|euros|euro))?/);
  if (m) {
    // Normalizar: quitar puntos miles, coma decimal → punto
    const cleaned = m[1].replace(/\./g, '').replace(',', '.');
    const target = parseFloat(cleaned);
    if (!isNaN(target) && target > 0) {
      // Tolerancia: si user dijo "289", matchear 289.19 también (integer prefix).
      for (let i = 0; i < items.length; i++) {
        const t = Number(items[i].total) || 0;
        if (Math.abs(t - target) < 0.5) {
          resolvedIndex = i + 1;
          matchedBy = 'importe_exact';
          break;
        }
        // Si user dijo entero (sin decimales) y total es ese entero + decimales <1
        if (!m[1].includes(',') && !m[1].includes('.') && Math.floor(t) === target) {
          resolvedIndex = i + 1;
          matchedBy = 'importe_int';
          break;
        }
      }
    }
  }
}

// ── 5) CLIENTE (solo si listado tiene clientes MIXTOS) ──
if (resolvedIndex === null) {
  const uniqClientes = new Set(items.map(it => String(it.cliente_nombre || '').toLowerCase()));
  if (uniqClientes.size > 1) {
    // "el de Borja" / "para Borja" / "de Manuel"
    const m = text.match(/\b(?:el\s+de|para|de)\s+([a-z][a-z\s]{1,30})/);
    if (m) {
      const target = m[1].trim().split(/\s+/)[0]; // primer token (nombre)
      for (let i = 0; i < items.length; i++) {
        const c = String(items[i].cliente_nombre || '').toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '');
        if (c.includes(target)) {
          resolvedIndex = i + 1;
          matchedBy = 'cliente';
          break;
        }
      }
    }
  }
}

// ── 6) NÚMERO de slot ──
if (resolvedIndex === null) {
  // "el 1" / "la 2" / "#3" / "n° 4" / "numero 5"
  let m = text.match(/(?:^|\s)(?:el|la|numero|n[oº°]|#)\s*(\d{1,2})\b/);
  if (!m) {
    // N suelto al inicio del mensaje (user escribe solo "1" o "1.")
    m = text.match(/^\s*(\d{1,2})\s*\.?\s*$/);
  }
  if (m) {
    const n = parseInt(m[1], 10);
    if (n >= 1 && n <= items.length) {
      resolvedIndex = n;
      matchedBy = 'numero';
    }
  }
}

// ── 7) ORDINAL ──
if (resolvedIndex === null) {
  const ORDINALS = {
    'primero': 1, 'primera': 1, 'primer': 1,
    'segundo': 2, 'segunda': 2,
    'tercero': 3, 'tercera': 3, 'tercer': 3,
    'cuarto': 4, 'cuarta': 4,
    'quinto': 5, 'quinta': 5,
  };
  if (/\b(ultimo|ultima)\b/.test(text)) {
    resolvedIndex = items.length;
    matchedBy = 'ordinal_last';
  } else {
    for (const ord in ORDINALS) {
      const re = new RegExp('\\b' + ord + '\\b');
      if (re.test(text)) {
        const n = ORDINALS[ord];
        if (n <= items.length) {
          resolvedIndex = n;
          matchedBy = 'ordinal';
        }
        break;
      }
    }
  }
}

// ── 8) PRONOMBRE / 1-item shortcut ──
if (resolvedIndex === null && items.length === 1) {
  // "ese", "ese mismo", "el de antes", "ese de antes"
  // O preguntas de detalle con 1 solo candidato.
  if (
    /\b(ese|esa|el\s+de\s+antes|el\s+anterior|el\s+mismo)\b/.test(text) ||
    /\b(que\s+tiene|que\s+inclu|que\s+lleva|mas\s+detalle|abre|abrir|ver|muestra|cuanto)\b/.test(text)
  ) {
    resolvedIndex = 1;
    matchedBy = 'shortcut_unico';
  }
}

if (resolvedIndex === null) {
  return [{ json: upstream }];
}

const item = items[resolvedIndex - 1];
const newStateJson = {
  ...(stateJson || {}),
  resolved_slot: {
    index: resolvedIndex,
    id: item.id,
    num: item.num,
    cliente_nombre: item.cliente_nombre,
    total: item.total,
    fecha: item.fecha,
    kind: stateJson.last_listado.kind || 'presupuestos',
    matched_by: matchedBy,
    ts: new Date().toISOString(),
  },
};

return [{ json: { ...upstream, previous_state_json: newStateJson } }];

