// PR_BOT_3: tras cancelar, fuerza chat_state.current_view='idle' para no quedar
// 'awaiting_confirmation' hasta TTL 90s. Fail-open (no rompe el reply de cancel).
const BASE = $env.FACTURAIA_BASE_URL || $env.APP_URL || 'https://app.tufacturaia.com';
const parsed = $('Parsear Mensaje').first().json;

const _phRaw = (parsed.normalized_phone || '').trim();
const phoneUser = _phRaw && !_phRaw.startsWith('+') ? '+' + _phRaw.replace(/^\++/, '') : _phRaw;
const phoneReceptorId = parsed.phone_number_id || '';

if (!BASE || !SIGNING_SECRET || !phoneUser || !phoneReceptorId) {
  return [{ json: { ...$json, pr_bot_3_clear_skip: 'missing_env_or_phone' } }];
}

let orgId = '';
try {
  const ctx = await signedHttpRequest.call(this, {
    method: 'POST',
    url: BASE + '/api/internal/whatsapp/resolve-context',
    headers: { 'Content-Type': 'application/json' },
    body: { from_phone: phoneUser },
    json: true,
    timeout: 3000,
  });
  if (ctx && ctx.matched && ctx.org_id) orgId = ctx.org_id;
} catch (_err) {
  return [{ json: { ...$json, pr_bot_3_clear_skip: 'resolve_context_error' } }];
}

if (!orgId) {
  return [{ json: { ...$json, pr_bot_3_clear_skip: 'no_org_matched' } }];
}

try {
  await signedHttpRequest.call(this, {
    method: 'POST',
    url: BASE + '/api/internal/voice/chat-state',
    headers: { 'Content-Type': 'application/json' },
    body: {
      phone_user: phoneUser,
      phone_receptor_id: phoneReceptorId,
      org_id: orgId,
      current_view: 'idle',
      state_json: { draft: null, last_intent: 'cancel', ts: new Date().toISOString() },
    },
    json: true,
    timeout: 3000,
  });
  return [{ json: { ...$json, pr_bot_3_clear_ok: true } }];
} catch (err) {
  return [{ json: { ...$json, pr_bot_3_clear_skip: 'chat_state_post_error', pr_bot_3_err: String((err && err.message) || err).slice(0, 120) } }];
}

