// Procesa una ingesta pendiente tras elegir empresa (carga directa multi-org).
// El cuerpo OCR ('const systemPrompt' en adelante) es IDÉNTICO a 'Disparar OCR'
// (spliced por apply-ingesta-hardening.py). NO editar a mano: re-correr el patch.

const SUPABASE_URL = 'https://lahqlyaxvobqjgdiftag.supabase.co';
const SUPABASE_KEY = $env.SUPABASE_SERVICE_ROLE_KEY;
const hdr = { apikey: SUPABASE_KEY, Authorization: 'Bearer ' + SUPABASE_KEY, 'Content-Type': 'application/json' };

const parsedMsg = $('Parsear Mensaje').first().json;
const phone = parsedMsg.normalized_phone;
const fromRaw = parsedMsg.from;
const fromName = parsedMsg.from_name;
const selectedOrgId = (parsedMsg.list_reply_id || '').replace('org_select:', '');

// Guard anti-cross-tenant: solo ingerir si select-org (Cambiar Sticky Org) validó
// membership y devolvió ok:true. Si alguien pusiera onError en ese nodo, sin este
// guard se podría escribir en una org sin pertenencia.
const sticky = $('Cambiar Sticky Org').first().json;
if (!sticky || sticky.ok !== true) {
  return [{ json: { has_pending: false } }];
}

const pendRows = await signedHttpRequest.call(this, { method: 'GET', url: SUPABASE_URL + '/rest/v1/whatsapp_pending_ingesta?phone=eq.' + encodeURIComponent(phone) + '&expires_at=gt.' + encodeURIComponent(new Date().toISOString()) + '&order=created_at.desc&limit=1', headers: hdr, json: true });
if (!pendRows || pendRows.length === 0) {
  return [{ json: { has_pending: false } }];
}
const pendiente = pendRows[0];

let orgNombre = '';
try {
  const orgs = await signedHttpRequest.call(this, { method: 'GET', url: SUPABASE_URL + '/rest/v1/organizations?id=eq.' + selectedOrgId + '&select=nombre', headers: hdr, json: true });
  orgNombre = ((orgs && orgs[0] && orgs[0].nombre) || '').replace(/[<>{}[\]\\]/g, '').slice(0, 120);
} catch (e) {}

// filename ya saneado al crear el pendiente; re-saneo defensivo al leerlo.
const filename = (pendiente.filename || 'documento').replace(/[^a-zA-Z0-9.\-_]/g, '_').slice(0, 200);
const destPath = selectedOrgId + '/' + Date.now() + '-' + filename;
await signedHttpRequest.call(this, { method: 'POST', url: SUPABASE_URL + '/storage/v1/object/copy', headers: hdr, body: { bucketId: 'facturas', sourceKey: pendiente.storage_path, destinationKey: destPath }, json: true });

const arr = await signedHttpRequest.call(this, { method: 'GET', url: SUPABASE_URL + '/storage/v1/object/facturas/' + destPath, headers: { apikey: SUPABASE_KEY, Authorization: 'Bearer ' + SUPABASE_KEY }, encoding: 'arraybuffer' });
const b64 = Buffer.from(arr).toString('base64');
const mime = pendiente.mime_type || 'image/jpeg';
const documentoUrl = SUPABASE_URL + '/storage/v1/object/public/facturas/' + destPath;

const facturaRows = await signedHttpRequest.call(this, { method: 'POST', url: SUPABASE_URL + '/rest/v1/facturas', headers: Object.assign({}, hdr, { Prefer: 'return=representation' }), body: { org_id: selectedOrgId, tipo: 'recibida', estado: 'sin_aprobar', num: 'WA-' + fromRaw + '-' + Date.now(), serie: 'R', base: 0, iva_pct: 21, total: 0, fuente: 'whatsapp', documento_url: documentoUrl, fecha: new Date().toISOString().slice(0, 10), vto: new Date().toISOString().slice(0, 10), created_via: 'ocr' }, json: true });
const facturaId = facturaRows && facturaRows[0] && facturaRows[0].id;

const bandejaRows = await signedHttpRequest.call(this, { method: 'POST', url: SUPABASE_URL + '/rest/v1/bandeja_ingesta', headers: Object.assign({}, hdr, { Prefer: 'return=representation' }), body: { org_id: selectedOrgId, fuente: 'whatsapp', emisor: (pendiente.from_name || fromName || '') + ' (' + fromRaw + ')', nombre_archivo: filename, documento_url: documentoUrl, progreso: 0, estado: 'procesando', factura_id: facturaId }, json: true });
const bandejaRow = (bandejaRows && bandejaRows[0]) || {};

// Borrar el pendiente (fila + fichero _pending) YA, antes del OCR: si el OCR falla,
// factura/bandeja quedan en 'procesando' (igual que Disparar OCR) pero sin duplicar
// en un reintento de selección.
try { await signedHttpRequest.call(this, { method: 'DELETE', url: SUPABASE_URL + '/rest/v1/whatsapp_pending_ingesta?id=eq.' + pendiente.id, headers: hdr, json: true }); } catch (e) {}
try { await signedHttpRequest.call(this, { method: 'DELETE', url: SUPABASE_URL + '/storage/v1/object/facturas/' + pendiente.storage_path.split('/').map(encodeURIComponent).join('/'), headers: { apikey: SUPABASE_KEY, Authorization: 'Bearer ' + SUPABASE_KEY } }); } catch (e) {}

// Dispara el OCR via webhook SSOT factura-ocr (mismo prompt versionado que
// upload/email/single-org: extrae lineas Fase D + multidivisa + guard NIF).
// El webhook (responseMode=lastNode) firma HMAC y delega en
// /api/internal/whatsapp/ocr-process, que persiste datos_extraidos + lineas +
// actualiza factura + audit server-side. Sustituye al OCR inline duplicado.
let ocrRes = null; // EXTRACTOS_MOV_V2: capturar descartado:true (036)
try {
  ocrRes = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://n8n.tufacturaia.com/webhook/factura-ocr',
    headers: { 'Content-Type': 'application/json' },
    body: {
      org_id: selectedOrgId,
      org_nombre: orgNombre,
      factura_id: facturaId,
      bandeja_id: bandejaRow.id,
      file_base64: b64,
      mime_type: mime,
      nombre_archivo: filename,
    },
    json: true,
    timeout: 90000,
  });
} catch (e) {
  // Fallo de transporte al disparar OCR (el webhook maneja errores OCR server-side).
  // Marca la bandeja para revision humana para que no quede colgada en 'procesando'.
  try { await signedHttpRequest.call(this, { method: 'PATCH', url: SUPABASE_URL + '/rest/v1/bandeja_ingesta?id=eq.' + bandejaRow.id, headers: { apikey: SUPABASE_KEY, Authorization: 'Bearer ' + SUPABASE_KEY, 'Content-Type': 'application/json' }, body: { estado: 'revisar', requires_human_review: true, review_reasons: ['ocr_trigger_error'] }, json: true }); } catch (e2) {}
}
// Carga directa OK: devolver para confirmar al usuario.
return [{ json: { has_pending: true, org_nombre: orgNombre, factura_id: facturaId, bandeja_id: bandejaRow && bandejaRow.id, org_id: selectedOrgId, ocr_descartado: !!(ocrRes && ocrRes.descartado), ocr_mensaje: (ocrRes && ocrRes.mensaje) || null } }];

