try { stickyOk = $('Cambiar Sticky Org').first().json.ok === true; } catch (e) { stickyOk = false; }
if (!stickyOk) { try { stickyOk = $('Cambiar Sticky Auto').first().json.ok === true; } catch (e) {} }
if (!stickyOk) return [{ json: { has_pending_msg: false, _skip: 'sticky_not_ok' } }];

// Lee el pendiente vivo más reciente.
let rows = [];
try {
  rows = await this.helpers.httpRequest({
    method: 'GET',
    url: `${SUPABASE_URL}/rest/v1/whatsapp_pending_mensaje?phone=eq.${encodeURIComponent(phone)}&expires_at=gt.${new Date().toISOString()}&created_at=gt.${new Date(Date.now() - 10*60*1000).toISOString()}&order=created_at.desc&limit=1`,
    headers: hdr, json: true,
  });
} catch (e) { return [{ json: { has_pending_msg: false, _err: 'read_failed' } }]; }
if (!rows || !rows.length) return [{ json: { has_pending_msg: false } }];
const pend = rows[0];

// Resuelve org (la sticky recién fijada manda) para el contexto del agente.
let ctx;
try {
  ctx = await signedHttpRequest.call(this, {
    method: 'POST',
    url: `${BASE}/api/internal/whatsapp/resolve-context`,
    body: { from_phone: phone, features_to_check: ['generador_voz'] },
    json: true,
  });
} catch (e) { return [{ json: { has_pending_msg: false, _err: 'resolve_failed' } }]; }
if (!ctx || ctx.matched !== true || !ctx.org_id) {
  return [{ json: { has_pending_msg: false, _err: 'not_matched' } }];
}

// Borra el pendiente (un solo uso).
try {
  await this.helpers.httpRequest({
    method: 'DELETE',
    url: `${SUPABASE_URL}/rest/v1/whatsapp_pending_mensaje?id=eq.${pend.id}`,
    headers: hdr, json: false,
  });
} catch (e) { /* no bloqueante; el cron purga */ }

// Item shaped para Preparar Input Agente (Set lee $json.*).
return [{ json: {
  has_pending_msg: true,
  transcription: pend.text_body,
  normalized_phone: phone,
  raw_from: parsed.from,
  phone_number_id: parsed.phone_number_id || pend.phone_number_id || null,
  org_id: ctx.org_id,
  org_nombre: ctx.org_nombre,
  memberships_count: ctx.memberships_count || 1,
  candidate_orgs: ctx.candidate_orgs || null,
  is_first_time: false,
  previous_state_json: null,
} }];

// Reporta uso/coste ESTIMADO del turno LLM a FacturaIA (/api/voice/usage) para
// el dashboard /admin/ia-ops (tab WhatsApp). Fire-and-forget: NUNCA rompe la
// conversación (todo en try/catch + nodo con onError=continueRegularOutput).
//
// El LLM corre aquí (n8n), así que el backend no ve los tokens: los estimamos
// con la misma heurística chars/divisor que el backend (estimateTokens en
// ai-enrich.ts → in=3.5, out=3). Es una estimación MÍNIMA: no incluye el system
// prompt completo ni los pasos intermedios de tool-calling del agente. El conteo
// de mensajes (1 fila por turno) sí es exacto. Idempotente por wamid.
const crypto = require('crypto');
try {
  const SIGNING_SECRET = $env.FACTURAIA_SIGNING_SECRET;
  const APP_URL = $env.APP_URL;
  if (SIGNING_SECRET && APP_URL) {
    const prep = $('Preparar Input Agente').first().json;
    const parsed = $('Parsear Mensaje').first().json;
    const org_id = prep && prep.org_id;
    const chat_id = (prep && prep.sessionId) || (parsed && parsed.normalized_phone) || '';
    const request_id = parsed && parsed.message_id; // wamid, único por mensaje

    if (org_id && request_id) {
      const inputText = String((prep && prep.chatInput) || '');
      const outputText = String($json.output || $json.text || '');
      const tokens_in = Math.ceil(inputText.length / 3.5);
      const tokens_out = Math.ceil(outputText.length / 3);

      const body = JSON.stringify({
        org_id: org_id,
        chat_id: chat_id,
        request_id: request_id,
        modelo: 'gpt-4o',
        tokens_in: tokens_in,
        tokens_out: tokens_out,
      });
      const t = Math.floor(Date.now() / 1000);
      const bodyHash = crypto.createHash('sha256').update(body, 'utf8').digest('hex');
      const sig = crypto
        .createHmac('sha256', SIGNING_SECRET)
        .update(t + '.POST./api/voice/usage.' + bodyHash, 'utf8')
        .digest('hex');
      await this.helpers.httpRequest({
        method: 'POST',
        url: APP_URL + '/api/voice/usage',
        headers: {
          'X-Service-Signature': 't=' + t + ',v1=' + sig,
          'Content-Type': 'application/json',
        },
        body: body,
        json: false,
      });
    }
  }
} catch (e) {
  console.error('[Reportar Uso WhatsApp]', (e && e.message) ? e.message : e);
}
return $input.all();

