// Apéndice 80% cuota mensajes — issue 003 cuotas-por-tier
// Se ejecuta tras el Agente Facturador. Si quota.warn80 && !quota.warn80_notified:
//   1. Añade línea de aviso al final de $json.output.
//   2. POST a chat-state marcando warn80_notified (clave mensual YYYY-MM).
// Si no aplica: pass-through.
const crypto = require('crypto');

// Leer quota del output del Resolver (texto o voz, el primero disponible).
let _quota = null;
try {
  _quota = $('Resolver Chat State Texto')?.first()?.json?.quota;
} catch {}
if (!_quota) {
  try { _quota = $('Resolver Chat State Voz')?.first()?.json?.quota; } catch {}
}

const _warn80 = !!(_quota && _quota.warn80);
const _warn80Notified = !!(_quota && _quota.warn80_notified);
const _used = _quota ? _quota.msgs_used : null;
const _cap = _quota ? _quota.msgs_cap : null;

const _items = $input.all();

if (!_warn80 || _warn80Notified) {
  // Sin apéndice — pass-through
  return _items;
}

// Añadir apéndice al output del agente
const _usedStr = _used != null ? String(_used) : '?';
const _capStr = _cap != null ? String(_cap) : '?';
const _apendice = `Has usado ${_usedStr} de ${_capStr} consultas este mes`;

const _patched = _items.map(item => {
  const out = item.json.output || item.json.text || '';
  return { json: { ...item.json, output: out ? (out + '\n\n' + _apendice) : _apendice } };
});

// POST a chat-state para marcar warn80_notified (una sola vez por mes)
// Formato exacto del route.ts: state_json.quota_warn80_notified = 'YYYY-MM'
try {
  const SIGNING_SECRET = $env.FACTURAIA_SIGNING_SECRET;
  const APP_URL = $env.APP_URL;
  if (SIGNING_SECRET && APP_URL) {
    const _parsedMsg = $('Parsear Mensaje').first().json;
    // org_id: tomarlo del Resolver disponible
    let _orgId = null;
    try { _orgId = $('Resolver Chat State Texto')?.first()?.json?.org_id; } catch {}
    if (!_orgId) { try { _orgId = $('Resolver Chat State Voz')?.first()?.json?.org_id; } catch {} }
    if (!_orgId) { try { _orgId = $('Buscar Org Texto')?.first()?.json?.org_id; } catch {} }
    if (!_orgId) { try { _orgId = $('Buscar Org Voz')?.first()?.json?.org_id; } catch {} }

    const _phoneUser = (() => {
      const raw = (_parsedMsg.normalized_phone || '').trim();
      return raw && !raw.startsWith('+') ? '+' + raw.replace(/^\++/, '') : raw;
    })();
    const _phoneReceptorId = _parsedMsg.phone_number_id || '';

    // Mes actual YYYY-MM (igual que quotaWarn80Key() en el backend)
    const _currentMonth = new Date().toISOString().slice(0, 7);

    const _body = {
      phone_user: _phoneUser,
      phone_receptor_id: _phoneReceptorId,
      org_id: _orgId,
      current_view: $('Resolver Chat State Texto')?.first()?.json?.previous_state
        || $('Resolver Chat State Voz')?.first()?.json?.previous_state
        || 'idle',
      state_json: { quota_warn80_notified: _currentMonth },
    };

    const bodyStr = JSON.stringify(_body);
    const t = Math.floor(Date.now() / 1000);
    const bodyHash = crypto.createHash('sha256').update(bodyStr, 'utf8').digest('hex');
    const sig = crypto
      .createHmac('sha256', SIGNING_SECRET)
      .update(`${t}.POST./api/internal/voice/chat-state.${bodyHash}`, 'utf8')
      .digest('hex');
    await this.helpers.httpRequest({
      method: 'POST',
      url: APP_URL + '/api/internal/voice/chat-state',
      headers: {
        'X-Service-Signature': `t=${t},v1=${sig}`,
        'Content-Type': 'application/json',
      },
      body: bodyStr,
      json: false,
    });
  }
} catch (e) {
  // Fire-and-forget: el apéndice ya salió al usuario; el POST es best-effort.
  console.error('[Apéndice Warn80] POST chat-state falló:', e && e.message);
}

return _patched;

