parameters.jsCode:
// Guarda la transcripción original del remitente multi-org en whatsapp_pending_mensaje
// para reinyectarla tras elegir empresa (no pedir "repíteme"). Gemelo de
// Persistir Mensaje Pendiente pero para el ramal de voz (lee Parsear Transcripcion).
const SUPABASE_URL = 'https://lahqlyaxvobqjgdiftag.supabase.co';
const SUPABASE_KEY = $env.SUPABASE_SERVICE_ROLE_KEY;
const hdr = { apikey: SUPABASE_KEY, Authorization: 'Bearer ' + SUPABASE_KEY, 'Content-Type': 'application/json' };
const parsed = $('Parsear Transcripcion').first().json;
const phone = parsed.normalized_phone;
const text = parsed.transcription || '';
if (phone && text) {
  try {
    await this.helpers.httpRequest({
      method: 'DELETE',
      url: `${SUPABASE_URL}/rest/v1/whatsapp_pending_mensaje?phone=eq.${encodeURIComponent(phone)}`,
      headers: hdr, json: false,
    });
    await this.helpers.httpRequest({
      method: 'POST',
      url: `${SUPABASE_URL}/rest/v1/whatsapp_pending_mensaje`,
      headers: hdr,
      body: JSON.stringify({
        phone,
        text_body: text,
        from_name: parsed.from_name || null,
        phone_number_id: parsed.phone_number_id || null,
      }),
    });
  } catch(e) { /* best-effort, no bloquear el flujo */ }
}
return $input.all();

// G5·A S1 — Canary: rutea el texto del número probador al copiloto (cerebro
// Next.js) ANTES del Agente Facturador. Cualquier fallo o teléfono distinto →
// pass-through al agente (comportamiento actual, cero regresión). Reversible:
// borrar este nodo y reconectar "Cuota Excedida Texto?" → "Preparar Texto Agente".
const crypto = require('crypto');

let data;
try {
  data = $input.first().json || {};
} catch (e) {
  return $input.all();
}

// Copiloto activo para todos los usuarios (rollout completo 2026-06-30).

try {
  const APP = $env.APP_URL || 'https://app.tufacturaia.com';
  const SIGNING_SECRET = $env.FACTURAIA_SIGNING_SECRET;
  const TOKEN = $env.META_WHATSAPP_ACCESS_TOKEN || $env.META_WHATSAPP_TOKEN;
  if (!SIGNING_SECRET || !TOKEN) return $input.all();

  // --- Llamada firmada (HMAC v2) al puente copiloto ---
  const path = '/api/internal/whatsapp/copiloto';
  const bodyObj = {
    phone_number_id: data.phone_number_id,
    from_phone: data.from || data.normalized_phone,
    message: data.text_body || '',
    org_id: data.org_id || null,
  };
  const bodyStr = JSON.stringify(bodyObj);
  const t = Math.floor(Date.now() / 1000);
  const bodyHash = crypto.createHash('sha256').update(bodyStr, 'utf8').digest('hex');
  const sigPayload = t + '.POST.' + path + '.' + bodyHash;
  const sig = crypto.createHmac('sha256', SIGNING_SECRET).update(sigPayload, 'utf8').digest('hex');

  const respRaw = await this.helpers.httpRequest({
    method: 'POST',
    url: APP + path,
    headers: { 'X-Service-Signature': 't=' + t + ',v1=' + sig, 'Content-Type': 'application/json' },
    body: bodyStr,
    json: false,
    returnFullResponse: true,
    timeout: 30000,
  });

  const status = respRaw && respRaw.statusCode;
  let resp = respRaw && respRaw.body;
  if (typeof resp === 'string') { try { resp = JSON.parse(resp); } catch (e) { resp = null; } }

  // Error técnico o intent no portado → al agente legacy (fallback).
  if (!resp || status >= 400 || resp.fallback_n8n_agent) return $input.all();

  // --- El copiloto resolvió: enviar a Meta y terminar la rama ---
  const to = String(data.from || data.normalized_phone);
  const metaUrl = 'https://graph.facebook.com/v21.0/' + data.phone_number_id + '/messages';
  let payload;
  if (resp.confirm) {
    payload = {
      messaging_product: 'whatsapp', to, type: 'interactive',
      interactive: {
        type: 'button',
        body: { text: String(resp.summary || '¿Confirmas?').slice(0, 1024) },
        action: { buttons: [
          { type: 'reply', reply: { id: 'copiloto_confirm:' + resp.pending_id, title: 'Confirmar' } },
          { type: 'reply', reply: { id: 'copiloto_cancel:' + resp.pending_id, title: 'Cancelar' } },
        ] },
      },
    };
  } else {
    const text = resp.text || resp.mensaje || 'Listo.';
    payload = { messaging_product: 'whatsapp', to, type: 'text', text: { body: String(text).slice(0, 4096), preview_url: false } };
  }

  await this.helpers.httpRequest({
    method: 'POST',
    url: metaUrl,
    headers: { Authorization: 'Bearer ' + TOKEN, 'Content-Type': 'application/json' },
    body: JSON.stringify(payload),
    json: false,
  });

  return []; // rama terminada: no continúa al agente
} catch (e) {
  // Nunca romper: ante cualquier fallo, cae al agente legacy.
  return $input.all();
}
